// リクエストからパラメータを抽出
const body = $input.first().json.body || {};
const id = String(body.id || '');
const excludeIds = body.excludeIds || [];
const needCategory = String(body.needCategory || '');
const zodiac = String(body.zodiac || '');
const element = String(body.element || '');

if (!id) {
  return [{ json: { error: 'id is required' } }];
}

return [{ json: { id, excludeIds, needCategory, zodiac, element } }];

// 取得したベクトルでカテゴリ＆星座優先フィルタ付き類似検索クエリを構築
// 星座優先ロジック（クライアントの誤入力に寛容）:
//  ① 星座がユーザーと一致 → 通す（element は不問）
//  ② 星座が空 AND element がユーザー or 空 → 通す
const fetchResponse = $input.first().json;
const params = $('Extract Params').first().json;
const id = params.id;
const needCategory = params.needCategory;
const zodiac = params.zodiac;
const element = params.element;

const record = fetchResponse.vectors?.[id];
if (!record || !record.values) {
  return [{ json: { recommendations: [] } }];
}

const query = {
  vector: record.values,
  topK: 30,
  includeMetadata: true
};

const filters = [];
if (needCategory) {
  filters.push({ category: { '$eq': needCategory } });
}

if (zodiac && element) {
  filters.push({
    '$or': [
      { zodiac: { '$in': [zodiac] } },
      {
        '$and': [
          { zodiac: { '$in': [''] } },
          { element: { '$in': [element, ''] } }
        ]
      }
    ]
  });
} else if (zodiac) {
  filters.push({ zodiac: { '$in': [zodiac, ''] } });
} else if (element) {
  filters.push({ element: { '$in': [element, ''] } });
}

if (filters.length === 1) {
  query.filter = filters[0];
} else if (filters.length > 1) {
  query.filter = { '$and': filters };
}

return [{ json: query }];

// excludeIds を除外して上位1件を返す（element/zodiac は配列を文字列化）
const matches = $input.first().json.matches || [];
const params = $('Extract Params').first().json;
const excludeIds = new Set(params.excludeIds || []);

const toArrStr = (v) => {
  if (Array.isArray(v)) return v.filter(s => s !== '').join(',');
  if (v === undefined || v === null) return '';
  return String(v);
};

const recommendations = [];
for (const match of matches) {
  if (excludeIds.has(match.id)) continue;
  recommendations.push({
    id: match.id,
    score: match.score,
    title: match.metadata?.title || '',
    body: match.metadata?.body || '',
    url: match.metadata?.url || '',
    category: match.metadata?.category || '',
    zodiac: toArrStr(match.metadata?.zodiac),
    element: toArrStr(match.metadata?.element),
    audio_url: match.metadata?.audio_url || ''
  });
  if (recommendations.length >= 1) break;
}

return [{ json: { recommendations } }];
